export enum UserRole {
  STUDENTE = 'studente',
  ASSOCIAZIONE = 'associazione',
  ADMIN = 'admin',
}

export enum EventCategory {
  PARTY = 'Party',
  SEMINAR = 'Seminar',
  CULTURE = 'Culture',
  SPORT = 'Sport',
  OTHER = 'Other'
}

export interface User {
  _id: string;
  email: string;
  name: string;
  role: UserRole;
  profileImage?: string; 
  surname?: string; // Only for students
  description?: string; // Only for associations
  socialLinks?: string; // Only for associations
  stripeAccountId?: string; // Only for associations
  stripeOnboardingComplete?: boolean; // Only for associations
  favorites?: string[]; // Array of Event IDs
  followedAssociations?: User[] | string[]; // Array of User IDs or populated Users
  followersCount?: number; // Only for associations
  isVerified?: boolean;
  isDeleted?: boolean; // For Admin view
  createdAt?: string;
}

export interface Event {
  _id: string;
  title: string;
  description: string;
  longDescription: string;
  image: string;
  date: string; // ISO Date string
  time: string;
  location: string;
  price: number;
  maxCapacity: number;
  ticketsSold: number;
  organization: User | string; // ID or populated object
  stripeAccountId: string;
  prLists?: string[]; // Array of PR list names
  category: EventCategory; 
  favoritesCount?: number;
  status?: 'active' | 'draft' | 'archived' | 'deleted';
  // New Academic Fields
  requiresMatricola?: boolean;
  requiresCorsoStudi?: boolean; // New field
  scanType?: 'entry_only' | 'entry_exit';
}

export interface Ticket {
  _id: string;
  event: Event; // Populated in the UI for wallet
  owner: string | User;
  ticketHolderName: string;
  qrCodeId: string;
  purchaseDate: string;
  prList?: string; // The list chosen during purchase
  used: boolean; // Has the ticket been scanned? (Legacy/Simple check)
  checkInDate?: string; // When was it scanned
  // New Fields
  matricola?: string;
  corsoStudi?: string; // New field
  entryTime?: string;
  exitTime?: string;
  status: 'valid' | 'entered' | 'completed' | 'archived' | 'deleted' | 'active'; // 'active' kept for legacy compatibility
}

export interface Report {
  _id: string;
  eventId: Event;
  reporterId: User;
  reason: string;
  status: 'pending' | 'resolved' | 'dismissed';
  createdAt: string;
}

export interface LoginResponse {
  token: string;
  user: User;
}

export interface CartItem {
  eventId: string;
  quantity: number;
}

declare global {
  interface Window {
    cloudinary: any;
  }
}

const mongoose = require('mongoose');

// --- USER SCHEMA ---
const userSchema = new mongoose.Schema({
  email: { 
    type: String, 
    required: true, 
    unique: true, 
    lowercase: true, 
    trim: true       
  },
  password: { type: String, required: true }, 
  name: { type: String, required: true },
  role: { type: String, enum: ['studente', 'associazione', 'admin'], required: true },
  profileImage: { type: String, default: '' },

  // Verification Status
  isVerified: { type: Boolean, default: false },

  // GDPR & Fiscal Compliance (Soft Delete)
  isDeleted: { type: Boolean, default: false },
  deletedAt: { type: Date },

  // Student specific
  surname: String,
  favorites: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Event' }], 
  followedAssociations: [{ type: mongoose.Schema.Types.ObjectId, ref: 'User' }], 

  // Web Push Subscription
  pushSubscription: {
    endpoint: String,
    keys: {
      p256dh: String,
      auth: String
    }
  },

  // Password Reset Fields
  resetPasswordToken: String,
  resetPasswordExpires: Date,

  // Association specific
  description: String,
  socialLinks: String,
  stripeAccountId: { type: String, default: '' }, 
  stripeOnboardingComplete: { type: Boolean, default: false },
  followersCount: { type: Number, default: 0 } 
}, { timestamps: true });

// --- NOTIFICATION SCHEMA ---
const notificationSchema = new mongoose.Schema({
  recipient: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  title: { type: String, required: true },
  message: { type: String, required: true },
  url: { type: String, default: '/' },
  isRead: { type: Boolean, default: false },
  relatedEvent: { type: mongoose.Schema.Types.ObjectId, ref: 'Event' } // Linked Event for visibility logic
}, { timestamps: true });

// --- EVENT SCHEMA ---
const eventSchema = new mongoose.Schema({
  title: { type: String, required: true },
  description: String,
  longDescription: String,
  image: String,
  date: { type: Date, required: true },
  time: String,
  location: String,
  price: { type: Number, required: true, default: 0 },
  maxCapacity: { type: Number, required: true },
  ticketsSold: { type: Number, default: 0 },
  category: { type: String, default: 'Other' },

  // Organization reference
  organization: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },

  // PR Lists
  prLists: [String],

  // Favorites Counter
  favoritesCount: { type: Number, default: 0 },

  // Status for soft delete/archiving
  status: { type: String, enum: ['active', 'draft', 'archived', 'deleted'], default: 'active' },

  // --- ACADEMIC / SEMINAR FEATURES ---
  requiresMatricola: { type: Boolean, default: false },
  requiresCorsoStudi: { type: Boolean, default: false }, // New Field
  scanType: { type: String, enum: ['entry_only', 'entry_exit'], default: 'entry_only' }
}, { timestamps: true });

// --- TICKET SCHEMA ---
const ticketSchema = new mongoose.Schema({
  event: { type: mongoose.Schema.Types.ObjectId, ref: 'Event', required: true },
  owner: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },

  ticketHolderName: { type: String, required: true },
  qrCodeId: { type: String, required: true, unique: true },
  purchaseDate: { type: Date, default: Date.now },
  prList: { type: String, default: 'Nessuna lista' },

  // Academic Fields
  matricola: { type: String },
  corsoStudi: { type: String }, // New Field
  entryTime: { type: Date },
  exitTime: { type: Date },

  used: { type: Boolean, default: false }, 
  checkInDate: Date, 

  // Stripe Data
  paymentIntentId: String,
  sessionId: String,

  status: { type: String, enum: ['active', 'valid', 'entered', 'completed', 'archived', 'deleted'], default: 'valid' }
}, { timestamps: true });

// --- ORDER SCHEMA ---
const orderSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  eventId: { type: mongoose.Schema.Types.ObjectId, ref: 'Event', required: true },
  ticketNames: [String], 
  ticketMatricolas: [String],
  ticketCorsoStudi: [String], // New Field
  prList: { type: String, default: 'Nessuna lista' },
  quantity: { type: Number, required: true },
  totalAmountCents: { type: Number, required: true },
  status: { type: String, enum: ['pending', 'completed', 'failed'], default: 'pending' },
  stripeSessionId: { type: String },

  createdAt: { type: Date, default: Date.now, expires: 86400 } 
});

// --- REPORT SCHEMA (UGC) ---
const reportSchema = new mongoose.Schema({
  eventId: { type: mongoose.Schema.Types.ObjectId, ref: 'Event', required: true },
  reporterId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  reason: { type: String, required: true },
  status: { type: String, enum: ['pending', 'resolved', 'dismissed'], default: 'pending' },
  createdAt: { type: Date, default: Date.now }
});

module.exports = {
  User: mongoose.model('User', userSchema),
  Event: mongoose.model('Event', eventSchema),
  Ticket: mongoose.model('Ticket', ticketSchema),
  Order: mongoose.model('Order', orderSchema),
  Notification: mongoose.model('Notification', notificationSchema),
  Report: mongoose.model('Report', reportSchema)
