                    <div className="prose prose-indigo text-gray-600 whitespace-pre-line leading-relaxed">
                        {event.longDescription}
                    </div>

                    <div className="mt-8 pt-8 border-t border-gray-100">
                         <h3 className="text-lg font-bold text-gray-900 mb-4">Organized by</h3>
                         <div className="flex items-center">
                             <div className="h-12 w-12 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-lg mr-4 overflow-hidden border border-gray-200">
                                {typeof event.organization === 'object' && 'profileImage' in event.organization && event.organization.profileImage ? (
                                    <img src={event.organization.profileImage} alt="Org" className="w-full h-full object-cover" />
                                ) : (
                                    <span>{typeof event.organization === 'object' ? (event.organization as any).name?.charAt(0) : 'A'}</span>
                                )}
                             </div>
                             <div>
                                 <Link to={`/association/${typeof event.organization === 'object' ? event.organization._id : event.organization}`} className="font-bold text-gray-900 text-lg hover:text-indigo-600 transition">
                                    {typeof event.organization === 'object' ? (event.organization as any).name : 'Association'}
                                 </Link>
                                 <p className="text-sm text-gray-500">Event Organizer</p>
                             </div>
                         </div>
                    </div>
                </div>
            </div>

            {/* Right Column: Ticket Selection */}
            <div className="lg:col-span-1">
                <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-200 sticky top-24">
                     {/* Price Header */}
                     <div className="flex justify-between items-center mb-6">
                         <div>
                             <p className="text-sm text-gray-500 font-medium">Prezzo per persona</p>
                             <h3 className="text-3xl font-bold text-gray-900">
                                 {isFree ? 'Gratis' : `€${finalPrice.toFixed(2)}`}
                             </h3>
                         </div>
                         {isAlmostSoldOut && (
                             <span className="bg-orange-100 text-orange-800 text-xs font-bold px-2 py-1 rounded-full animate-pulse">
                                 Ultimi posti!
                             </span>
                         )}
                     </div>

                     {/* Sales Controls */}
                     {isSoldOut ? (
                         <div className="bg-gray-100 rounded-lg p-4 text-center font-bold text-gray-500 mb-4">
                             SOLD OUT
                         </div>
                     ) : (
                         <div className="space-y-4">
                             {/* Quantity */}
                             <div className="flex items-center justify-between bg-gray-50 p-2 rounded-lg border border-gray-200">
                                 <span className="text-sm font-medium text-gray-700 ml-2">Quantità</span>
                                 <div className="flex items-center">
                                     <button 
                                        onClick={() => setQuantity(Math.max(1, quantity - 1))}
                                        className="p-2 bg-white rounded-md shadow-sm hover:bg-gray-100 text-indigo-600 disabled:opacity-50"
                                        disabled={quantity <= 1}
                                     >
                                         <Minus className="w-4 h-4" />
                                     </button>
                                     <span className="w-12 text-center font-bold text-gray-900">{quantity}</span>
                                     <button 
                                        onClick={() => setQuantity(Math.min(maxPurchaseLimit, quantity + 1))}
                                        className="p-2 bg-white rounded-md shadow-sm hover:bg-gray-100 text-indigo-600 disabled:opacity-50"
                                        disabled={quantity >= maxPurchaseLimit}
                                     >
                                         <Plus className="w-4 h-4" />
                                     </button>
                                 </div>
                             </div>

                             {/* Dynamic Inputs */}
                             <div className="space-y-3 max-h-60 overflow-y-auto pr-1">
                                 {Array.from({ length: quantity }).map((_, i) => (
                                     <div key={i} className="space-y-2 p-3 bg-gray-50 rounded-lg border border-gray-100">
                                         <p className="text-xs font-bold text-gray-500 uppercase">Voucher #{i + 1}</p>
                                         <input
                                             type="text"
                                             placeholder="Nome e Cognome"
                                             value={ticketNames[i]}
                                             onChange={e => handleNameChange(i, e.target.value)}
                                             className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                                         />
                                         {event.requiresMatricola && (
                                              <div className="flex items-center">
                                                  <GraduationCap className="w-4 h-4 mr-2 text-gray-400" />
                                                  <input
                                                      type="text"
                                                      placeholder="Matricola"
                                                      value={ticketMatricolas[i]}
                                                      onChange={e => handleMatricolaChange(i, e.target.value)}
                                                      className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                                                  />
                                              </div>
                                         )}
                                         {event.requiresCorsoStudi && (
                                              <div className="flex items-center">
                                                  <BookOpen className="w-4 h-4 mr-2 text-gray-400" />
                                                  <input
                                                      type="text"
                                                      placeholder="Corso di Studi"
                                                      value={ticketCorsoStudi[i]}
                                                      onChange={e => handleCorsoStudiChange(i, e.target.value)}
                                                      className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                                                  />
                                              </div>
                                         )}
                                     </div>
                                 ))}
                             </div>

                             {/* PR List Selector */}
                             {event.prLists && event.prLists.length > 0 && (
                                 <div>
                                     <label className="block text-sm font-medium text-gray-700 mb-1">Lista PR</label>
                                     <select
                                         value={selectedPrList}
                                         onChange={e => setSelectedPrList(e.target.value)}
                                         className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                                     >
                                         <option value="">Seleziona una lista...</option>
                                         <option value="Nessuna lista">Nessuna lista</option>
                                         {event.prLists.map(list => (
                                             <option key={list} value={list}>{list}</option>
                                         ))}
                                     </select>
                                 </div>
                             )}
                         </div>
                     )}

                     {/* Summary */}
                     <div className="border-t border-gray-100 my-4 pt-4 space-y-2">
                         <div className="flex justify-between text-sm text-gray-600">
                             <span>Biglietti x {quantity}</span>
                             <span>€{(priceInCents * quantity / 100).toFixed(2)}</span>
                         </div>
                         {!isFree && (
                             <div className="flex justify-between text-sm text-gray-600">
                                 <span className="flex items-center">Fee Servizio <Info className="w-3 h-3 ml-1 text-gray-400"/></span>
                                 <span>€{(feeInCents * quantity / 100).toFixed(2)}</span>
                             </div>
                         )}
                         <div className="flex justify-between text-lg font-bold text-gray-900 pt-2">
                             <span>Totale</span>
                             <span>€{totalAmount.toFixed(2)}</span>
                         </div>
                     </div>

                     {/* Terms Checkbox */}
                     {!isSoldOut && (
                         <div className="mb-4 flex items-start">
                             <input 
                                 id="terms" 
                                 type="checkbox" 
                                 checked={acceptedTerms}
                                 onChange={e => setAcceptedTerms(e.target.checked)}
                                 className="mt-1 h-4 w-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                             />
                             <label htmlFor="terms" className="ml-2 text-xs text-gray-500">
                                 Accetto i <Link to="/terms" className="text-indigo-600 hover:underline">Termini e Condizioni</Link>. 
                                 Comprendo che la fee di servizio non è rimborsabile.
                             </label>
                         </div>
                     )}

                     {/* Action Button */}
                     <button
                         onClick={handlePurchase}
                         disabled={isSoldOut || purchasing || (!isFree && !user)}
                         className={`w-full py-3 px-4 rounded-xl font-bold text-white shadow-lg transition transform active:scale-95 flex items-center justify-center ${
                             isSoldOut 
                             ? 'bg-gray-400 cursor-not-allowed' 
                             : 'bg-indigo-600 hover:bg-indigo-700'
                         }`}
                     >
                         {purchasing ? (
                             'Elaborazione...'
                         ) : isSoldOut ? (
                             'Sold Out'
                         ) : (
                             <>
                                Prenota Ora <ChevronRight className="w-4 h-4 ml-1" />
                             </>
                         )}
                     </button>

                     {!user && !isSoldOut && (
                         <p className="text-xs text-center text-gray-500 mt-2">
                             Devi effettuare il login per prenotare.
                         </p>
                     )}
                </div>

                {/* Additional Info / When & Where Small */}
                <div className="mt-6 bg-indigo-50 rounded-xl p-4 border border-indigo-100">
                    <h4 className="font-bold text-indigo-900 mb-2 flex items-center"><Info className="w-4 h-4 mr-2"/> Info Utili</h4>
                    <p className="text-xs text-indigo-800 mb-2">
                        Mostra il QR Code all'ingresso. Non serve stampare il biglietto.
                    </p>
                     <a 
                        href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(event.location)}`}
                        target="_blank" 
                        rel="noreferrer"
                        className="text-xs font-bold text-indigo-600 hover:underline flex items-center"
                     >
                         <MapPin className="w-3 h-3 mr-1" /> Apri Mappa
                     </a>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default EventDetails;

import React, { useEffect, useState } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { User, Event, Ticket, UserRole, Report } from '../types';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Shield, User as UserIcon, Calendar, CheckCircle, XCircle, Trash2, RefreshCw, Ticket as TicketIcon, Search, Eye, Filter, BarChart, X, TrendingUp, DollarSign, Heart, GraduationCap, Clock, Users, Flag, AlertTriangle } from 'lucide-react';

type UserFilter = 'all' | 'studente' | 'associazione';

const AdminDashboard: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  // Tab State derived from URL
  const activeTab = (searchParams.get('tab') as 'users' | 'events' | 'reports') || 'users';

  // Data State
  const [users, setUsers] = useState<User[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [userFilter, setUserFilter] = useState<UserFilter>('all');

  // Modal Ticket State
  const [isTicketModalOpen, setIsTicketModalOpen] = useState(false);
  const [selectedUserTickets, setSelectedUserTickets] = useState<Ticket[]>([]);
  const [selectedUserName, setSelectedUserName] = useState('');
  const [modalLoading, setModalLoading] = useState(false);

  // Modal Stats State
  const [isStatsModalOpen, setIsStatsModalOpen] = useState(false);
  const [selectedEventStats, setSelectedEventStats] = useState<{ [key: string]: number } | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [statsLoading, setStatsLoading] = useState(false);

  // Moderation Modal State
  const [isModModalOpen, setIsModModalOpen] = useState(false);
  const [modTargetEvent, setModTargetEvent] = useState<Event | null>(null);
  const [deleteReason, setDeleteReason] = useState('');
  const [isModLoading, setIsModLoading] = useState(false);

  useEffect(() => {
    // Access Control
    if (!user || user.role !== UserRole.ADMIN) {
        navigate('/');
        return;
    }

    fetchData();
  }, [user, navigate, activeTab]);

  const fetchData = async () => {
      setLoading(true);
      try {
          if (activeTab === 'users') {
              const data = await api.admin.getAllUsers();
              setUsers(data);
          } else if (activeTab === 'events') {
              const data = await api.admin.getAllEvents();
              setEvents(data);
          } else if (activeTab === 'reports') {
              const data = await api.reports.getAll();
              setReports(data);
          }
      } catch (e) {
          console.error("Admin fetch error", e);
      } finally {
          setLoading(false);
      }
  };

  const handleTabChange = (tab: 'users' | 'events' | 'reports') => {
      setSearchParams({ tab });
  };

  const handleVerifyUser = async (userId: string) => {
      if(!window.confirm("Cambiare stato di verifica utente?")) return;
      try {
          await api.admin.verifyUser(userId);
          fetchData(); // Refresh list
      } catch(e) {
          alert("Errore verifica utente");
      }
  };

  const handleRestoreUser = async (userId: string) => {
      if(!window.confirm("Ripristinare questo utente cancellato?")) return;
      try {
          await api.admin.restoreUser(userId);
          fetchData();
      } catch(e) {
          alert("Errore ripristino utente");
      }
  };

  const handleViewTickets = async (userId: string, userName: string) => {
      setIsTicketModalOpen(true);
      setSelectedUserName(userName);
      setModalLoading(true);
      try {
          const tickets = await api.admin.getUserTickets(userId);
          setSelectedUserTickets(tickets);
      } catch(e) {
          console.error("Failed to fetch tickets", e);
          setSelectedUserTickets([]);
      } finally {
          setModalLoading(false);
      }
  };

  const handleViewStats = async (event: Event) => {
      setIsStatsModalOpen(true);
      setSelectedEvent(event);
      setStatsLoading(true);
      try {
          const stats = await api.events.getEventStats(event._id);
          setSelectedEventStats(stats);
      } catch (e) {
          console.error("Failed to fetch stats", e);
          setSelectedEventStats(null);
      } finally {
          setStatsLoading(false);
      }
  };

  const handleOpenModeration = (event: Event) => {
      setModTargetEvent(event);
      setIsModModalOpen(true);
      setDeleteReason('');
  };

  const handleModDelete = async () => {
      if (!modTargetEvent || !deleteReason.trim()) return;
      setIsModLoading(true);
      try {
          await api.admin.deleteEventWithReason(modTargetEvent._id, deleteReason);
          alert("Evento rimosso e organizzatore notificato.");
          setIsModModalOpen(false);
          fetchData();
      } catch (err) {
          alert("Errore durante la rimozione.");
      } finally {
          setIsModLoading(false);
      }
  };

  const filteredUsers = users.filter(u => {
      const matchesSearch = u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            u.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRole = userFilter === 'all' || u.role === userFilter;
      return matchesSearch && matchesRole;
  });

  const filteredEvents = events.filter(e => 
      e.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (typeof e.organization === 'object' && e.organization.name.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const getTicketStatusBadge = (ticket: Ticket) => {
      if (ticket.status === 'entered') {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-yellow-100 text-yellow-800 border border-yellow-200">IN SALA</span>;
      }
      if (ticket.status === 'completed') {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-blue-100 text-blue-800 border border-blue-200">COMPLETATO</span>;
      }
      if (ticket.status === 'valid' || ticket.status === 'active' || (!ticket.used && !ticket.status)) {
          return <span className="px-3 py-1 rounded-full text-xs font-bold bg-green-100 text-green-800 border border-green-200">VALIDO</span>;
      }
      // Fallback legacy used
      return <span className="px-3 py-1 rounded-full text-xs font-bold bg-gray-100 text-gray-600 border border-gray-200">USATO</span>;
  };

  if (!user || user.role !== UserRole.ADMIN) return null;

  return (
    <div className="min-h-screen bg-gray-100 p-4 md:p-8">
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
            <div className="flex items-center">
                <Shield className="w-10 h-10 text-indigo-900 mr-3" />
                <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
            </div>
            <div className="bg-white rounded-lg shadow p-2 flex space-x-2">
                <button 
                    onClick={() => handleTabChange('users')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'users' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center">
                        <UserIcon className="w-4 h-4 mr-2" />
                        Utenti
                    </div>
                </button>
                <button 
                    onClick={() => handleTabChange('events')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'events' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center">
                        <Calendar className="w-4 h-4 mr-2" />
                        Eventi
                    </div>
                </button>
                <button 
                    onClick={() => handleTabChange('reports')}
                    className={`px-4 py-2 rounded-md font-medium transition ${activeTab === 'reports' ? 'bg-red-600 text-white' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <div className="flex items-center">
                        <Flag className="w-4 h-4 mr-2" />
                        Segnalazioni
                    </div>
                </button>
            </div>
        </div>

        {/* Filter Bar */}
        {activeTab !== 'reports' && (
            <div className="mb-6 flex flex-col md:flex-row gap-4">
                <div className="relative flex-grow">
                    <input 
                        type="text"
                        placeholder={activeTab === 'users' ? "Cerca utente per nome o email..." : "Cerca evento per titolo o organizzatore..."}
                        className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    <Search className="w-5 h-5 text-gray-400 absolute left-3 top-3.5" />
                </div>

                {activeTab === 'users' && (
                    <div className="flex items-center bg-white border border-gray-300 rounded-xl px-3 py-2 shadow-sm">
                        <Filter className="w-5 h-5 text-gray-500 mr-2" />
                        <select 
                            value={userFilter}
                            onChange={(e) => setUserFilter(e.target.value as UserFilter)}
                            className="bg-transparent outline-none text-gray-700 font-medium cursor-pointer"
                        >
                            <option value="all">Tutti i Ruoli</option>
                            <option value="studente">Studenti</option>
                            <option value="associazione">Associazioni</option>
                        </select>
                    </div>
                )}
            </div>
        )}

        {/* Content */}
        <div className="bg-white rounded-xl shadow-lg overflow-hidden border border-gray-200">
            {loading ? (
                <div className="p-12 text-center text-gray-500">Caricamento dati...</div>
            ) : (
                <>
                   {activeTab === 'users' && (
                       <div className="overflow-x-auto">
                           <table className="min-w-full divide-y divide-gray-200">
                               <thead className="bg-gray-50">
                                   <tr>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Utente</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ruolo</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stato</th>
                                       <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Azioni</th>
                                   </tr>
                               </thead>
                               <tbody className="bg-white divide-y divide-gray-200">
                                   {filteredUsers.map(u => (
                                       <tr key={u._id} className={u.isDeleted ? 'bg-red-50' : ''}>
                                           <td className="px-6 py-4 whitespace-nowrap">
                                               <div className="flex items-center">
                                                   <div className="flex-shrink-0 h-10 w-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold">
