        <div className="absolute inset-0 bg-gradient-to-t from-gray-900/80 to-transparent"></div>

        <div className="absolute top-24 right-4 sm:right-8 flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-2 z-20">
            {isOwner ? (
